import{_ as t,o as a,c as l,a2 as o}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"管理层选择 Selecting Management","description":"跟对人，是投资成功的第一步","frontmatter":{"title":"管理层选择 Selecting Management","description":"跟对人，是投资成功的第一步"},"headers":[],"relativePath":"02_concepts/management.md","filePath":"02_concepts/management.md"}'),r={name:"02_concepts/management.md"};function h(p,e,n,i,s,m){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="管理层选择-selecting-management" tabindex="-1">管理层选择 Selecting Management <a class="header-anchor" href="#管理层选择-selecting-management" aria-label="Permalink to &quot;管理层选择 Selecting Management&quot;">​</a></h1><blockquote><p>&quot;在我挑选股票时，管理层的重要性占49%。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1983年/核心总结</td><td style="text-align:left;">1983年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1995年/核心总结</td><td style="text-align:left;">1995年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1998年/核心总结</td><td style="text-align:left;">1998年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2005年/核心总结</td><td style="text-align:left;">2005年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2008年/核心总结</td><td style="text-align:left;">2008年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2015年/核心总结</td><td style="text-align:left;">2015年]]**</td></tr></tbody></table><hr><h2 id="为什么管理层如此重要" tabindex="-1">为什么管理层如此重要？ <a class="header-anchor" href="#为什么管理层如此重要" aria-label="Permalink to &quot;为什么管理层如此重要？&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>曾多次在致股东信中阐述一个核心观点：<strong>投资一家公司，本质上是投资这家公司背后的人</strong>。同样的资产，在不同管理水平下，可以产生天壤之别的回报。</p><p>他以<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>自身的经历为例：1965年收购<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦纺织厂时，这家企业在糟糕的管理层手下苟延残喘；而换入新的管理理念后，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>旗下的保险和投资业务蓬勃发展，成为了全球最值钱的公司之一。</p><blockquote><p>&quot;我们收购的不是工厂和机器——工厂和机器可以复制。我们收购的是人，以及这些人所代表的文化、能力和诚信。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1983年</p></blockquote><p>这个认知贯穿了<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>六十余年的投资生涯。他不仅是一位伟大的投资者，更是一位识人、用人、爱才的伯乐。</p><hr><h2 id="巴菲特选择管理层的标准" tabindex="-1"><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>选择管理层的标准 <a class="header-anchor" href="#巴菲特选择管理层的标准" aria-label="Permalink to &quot;[[巴菲特]]选择管理层的标准&quot;">​</a></h2><h3 id="标准一-诚信——不可撼动的底线" tabindex="-1">标准一：诚信——不可撼动的底线 <a class="header-anchor" href="#标准一-诚信——不可撼动的底线" aria-label="Permalink to &quot;标准一：诚信——不可撼动的底线&quot;">​</a></h3><p>在<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的管理层评估体系中，<strong>诚信是唯一不可妥协的标准</strong>。没有诚信，无论能力多强，都是不值得信任的人。</p><blockquote><p>&quot;我们在评估管理层时，首先问一个问题：如果我知道他们明天就会离开，我还会不会愿意把资金托付给他们？如果答案是否定的，那就一票否决。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1996年</p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的诚信测试标准极为严格：他期望管理层像对待自己的钱一样对待股东的钱，像对待自己的家人一样对待客户和员工。</p><blockquote><p>&quot;能力平平但诚信可靠的管理层，比能力超强但诚信可疑的管理层，更值得托付资金。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1993年</p></blockquote><p>这番话背后隐藏着深刻的洞察：能力不足可以通过招聘更强的人来弥补，但诚信一旦出问题，整个组织的根基就会动摇。</p><h3 id="标准二-理性——资本配置的智慧" tabindex="-1">标准二：理性——资本配置的智慧 <a class="header-anchor" href="#标准二-理性——资本配置的智慧" aria-label="Permalink to &quot;标准二：理性——资本配置的智慧&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的第二个核心标准是<strong>理性</strong>——管理层是否具备良好的资本配置能力，以及是否在做决策时保持理性而非被私心或面子所驱动。</p><blockquote><p>&quot;一家理性的公司，管理层会坦诚地告诉股东公司的真实状况；会把所有选项摆在桌面上讨论；会在资本配置时始终以股东利益为导向。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1996年</p></blockquote><p>他尤其看重管理层在面对&quot;是否分红&quot;和&quot;是否回购&quot;这类决策时的理性程度。一个理性的管理层，会在股价低估时积极回购，在股价高估时谨慎投资——而不是随波逐流或迎合短期情绪。</p><h3 id="标准三-坦诚——不回避问题" tabindex="-1">标准三：坦诚——不回避问题 <a class="header-anchor" href="#标准三-坦诚——不回避问题" aria-label="Permalink to &quot;标准三：坦诚——不回避问题&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对坦诚品质的重视，超出了大多数人的预期。他直言不讳地说：</p><blockquote><p>&quot;我最欣赏的管理者，是那些能直接告诉我&#39;我们遇到了问题&#39;的人；我最担心的管理者，是那些只会报喜不报忧的人。坦诚不仅是一种品质，更是一种效率——它能让我们更快地解决问题。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2005年</p></blockquote><p>在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的各子公司负责人中，这种坦诚文化根深蒂固。每年的年会上，<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>都会鼓励各业务负责人直接讲述问题和挑战，而不是粉饰太平。</p><h3 id="标准四-激情——对业务的热爱" tabindex="-1">标准四：激情——对业务的热爱 <a class="header-anchor" href="#标准四-激情——对业务的热爱" aria-label="Permalink to &quot;标准四：激情——对业务的热爱&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>偏爱那些真正热爱自己业务的管理者。他认为，<strong>发自内心的激情，是优秀管理层最重要的内在驱动力</strong>。</p><blockquote><p>&quot;当我看到一个 CEO 在谈论他的业务时眼睛发光，我能感受到那种真正的热爱。这种激情不是表演出来的——它是伪装不了的。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1997年</p></blockquote><p><a href="/03_companies/GEICO.html">盖可保险</a>的创始人利奥·古德温（Leo Goodwin）、<a href="/03_companies/喜诗糖果.html">喜诗糖果</a>的查尔斯·舒尔茨（Charles Schulz）……这些<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>长期持有的企业家，几乎无一不是对自己业务的狂热爱好者和完美主义者。</p><h3 id="标准五-独立思考——不被华尔街左右" tabindex="-1">标准五：独立思考——不被华尔街左右 <a class="header-anchor" href="#标准五-独立思考——不被华尔街左右" aria-label="Permalink to &quot;标准五：独立思考——不被华尔街左右&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>还特别看重管理层是否具备<strong>独立思考的能力</strong>，而不被华尔街分析师、机构投资者或短期股价波动所左右。</p><blockquote><p>&quot;华尔街会给你压力，让你做很多看起来合理但实际上在摧毁价值的事情。真正优秀的 CEO ，是那些能够在压力下保持独立判断，不为短期舆论所动的人。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2000年</p></blockquote><p>这与<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>本人&quot;在别人恐惧时贪婪，在别人贪婪时恐惧&quot;的哲学一脉相承。</p><hr><h2 id="识别优秀管理层的实用方法" tabindex="-1">识别优秀管理层的实用方法 <a class="header-anchor" href="#识别优秀管理层的实用方法" aria-label="Permalink to &quot;识别优秀管理层的实用方法&quot;">​</a></h2><h3 id="方法一-阅读年报——看管理层说了什么、没说什么" tabindex="-1">方法一：阅读年报——看管理层说了什么、没说什么 <a class="header-anchor" href="#方法一-阅读年报——看管理层说了什么、没说什么" aria-label="Permalink to &quot;方法一：阅读年报——看管理层说了什么、没说什么&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的建议是：仔细阅读一家公司过去十年的年报，特别关注管理层对过去的预测是否准确，以及他们如何解释成功与失败。</p><blockquote><p>&quot;年报的遣词造句能告诉我们很多——好的管理者会坦诚地讨论问题；糟糕的管理者会用空洞的套话掩盖问题。读年报就像读人心。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1992年</p></blockquote><h3 id="方法二-观察资本配置行为——钱花在哪里了" tabindex="-1">方法二：观察资本配置行为——钱花在哪里了 <a class="header-anchor" href="#方法二-观察资本配置行为——钱花在哪里了" aria-label="Permalink to &quot;方法二：观察资本配置行为——钱花在哪里了&quot;">​</a></h3><p>管理层的资本配置决策，最能暴露其真实能力和动机。关注以下几点：</p><ul><li>回购股票的时机和价格</li><li>收购决策是否创造了价值</li><li>何时选择分红而非乱投资</li><li>多元化扩张是否理性</li></ul><h3 id="方法三-与管理层的-一次握手" tabindex="-1">方法三：与管理层的&quot;一次握手&quot; <a class="header-anchor" href="#方法三-与管理层的-一次握手" aria-label="Permalink to &quot;方法三：与管理层的&quot;一次握手&quot;&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的另一个独特建议是：<strong>在你买入股票之前，想象一下你是否愿意和这个 CEO 做邻居</strong>。</p><blockquote><p>&quot;如果你不愿意和这个人做邻居，不愿意把女儿嫁给他，那为什么要把钱交给他管理？&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>这句话初听玩笑，实则蕴含了深刻的识人之道。</p><hr><h2 id="优秀管理层案例-盖可保险的利奥·古德温" tabindex="-1">优秀管理层案例：<a href="/03_companies/GEICO.html">盖可保险</a>的利奥·古德温 <a class="header-anchor" href="#优秀管理层案例-盖可保险的利奥·古德温" aria-label="Permalink to &quot;优秀管理层案例：[[盖可保险]]的利奥·古德温&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>最经典的管理层投资案例之一，是对<a href="/03_companies/GEICO.html">盖可保险</a>创始人利奥·古德温的信任。</p><blockquote><p>&quot;利奥是一个从不妥协的人——他坚持只向好司机卖保险，坚持用低成本模式运营，坚持用节省下来的钱让利给客户。这种坚持了五十年的商业模式，正是<a href="/03_companies/GEICO.html">盖可保险</a>护城河的核心。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1995年</p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在1960年代开始买入<a href="/03_companies/GEICO.html">盖可保险</a>，并最终完全收购。支撑他做出这一决定的，不仅是财务数据，更是利奥·古德温身上体现出的诚信、理性与激情。</p><hr><h2 id="警惕危险信号" tabindex="-1">警惕危险信号 <a class="header-anchor" href="#警惕危险信号" aria-label="Permalink to &quot;警惕危险信号&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>也总结了管理层危险信号的&quot;红旗&quot;（Red Flags）：</p><ul><li><strong>花言巧语</strong>：管理层在业绩好时邀功，业绩差时甩锅</li><li><strong>数据操纵</strong>：利用会计准则的灰色地带美化报表</li><li><strong>过度自信</strong>：频繁发起代价高昂的并购</li><li><strong>缺乏专注</strong>：核心业务还没做好，就四处扩张</li><li><strong>关联交易</strong>：与关联方频繁进行可疑的往来交易</li></ul><blockquote><p>&quot;一家公司可以没有完美的财务数据，但不能没有值得信任的管理层。数据不好，我们还有改进的机会；信任没有了，一切就结束了。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2008年</p></blockquote><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>选择管理层的标准，看似朴素，实则深刻——诚信、理性、坦诚、激情、独立思考。这五个标准共同构成了他对管理层的完整画像。</p><p>对于普通投资者而言，理解这些标准不仅仅是为了筛选股票，更是一种值得借鉴的识人智慧：无论是选择合作伙伴、投资对象，还是在职场中选择追随的领导，这些原则都有其普适价值。</p><p><strong>跟对人，是投资成功的第一步——也是最重要的一步。</strong></p>',62)])])}const q=t(r,[["render",h]]);export{u as __pageData,q as default};
